	DeleteAgentNote(context.Context, *DeleteAgentNoteRequest) (*DeleteAgentNoteResponse, error)
	SetAgentNoteInContext(context.Context, *SetAgentNoteInContextRequest) (*SetAgentNoteInContextResponse, error)
